function getNextRetryDate(repeatCount) {
  const date = /* @__PURE__ */ new Date();
  switch (repeatCount) {
    case 0:
      date.setDate(date.getDate() + 1);
      break;
    // 1 day
    case 1:
      date.setDate(date.getDate() + 3);
      break;
    // 3 days
    case 2:
      date.setDate(date.getDate() + 7);
      break;
    // 7 days
    default:
      date.setDate(date.getDate() + 14);
      break;
  }
  return date.toISOString();
}

