function getPublicOrDistFile(fileName) {
  const distFile = path4.join(process.cwd(), "dist", fileName);
  if (fs5.existsSync(distFile)) return distFile;
  const publicFile = path4.join(process.cwd(), "public", fileName);
  if (fs5.existsSync(publicFile)) return publicFile;
  return null;
}
